#include <stdio.h>
#include <stdlib.h>

// Simulated memory and hardware components
#define MEMORY_SIZE 1024
unsigned char memory[MEMORY_SIZE];
unsigned char *boot_loader;
unsigned char *kernel_start;

// Bootstrap program - loads OS kernel
void bootstrap_loader(void) {
    printf("=== BOOTSTRAP SEQUENCE ===\n");

    // Step 1: Initialize basic hardware
    printf("1. BIOS: Initializing basic hardware...\n");
    printf("2. POST: Power-On Self Test passed\n");

    // Step 2: Locate boot device
    printf("3. Searching for bootable device...\n");
    printf("   Found: Primary Hard Disk\n");

    // Step 3: Load boot sector (512 bytes)
    printf("4. Loading boot sector (512 bytes)...\n");
    boot_loader = &memory[0];

    // Step 4: Execute boot loader
    printf("5. Boot loader executing...\n");

    // Step 5: Load OS kernel
    printf("6. Loading OS Kernel into memory at address 0x1000...\n");
    kernel_start = &memory[0x1000];
    printf("   Kernel loaded successfully\n");

    // Step 6: Jump to kernel
    printf("7. Transferring control to OS Kernel...\n");
    printf("=== BOOT COMPLETE ===\n\n");
}

// Initialize and start system
int main() {
    bootstrap_loader();

    printf("System Services Starting:\n");
    printf("  - Memory Management Unit initialized\n");
    printf("  - Process Scheduler initialized\n");
    printf("  - File System mounted\n");
    printf("  - Device Drivers loaded\n");
    printf("\nLOGIN PROMPT READY\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct {
    unsigned int base_register;
    unsigned int limit_register;
    int in_kernel_mode;
} MemoryProtectionUnit;

// Global protection registers
MemoryProtectionUnit pmu = {0, 0, 0};

// Initialize memory protection
void init_protection(unsigned int base, unsigned int limit) {
    pmu.base_register = base;
    pmu.limit_register = limit;
    pmu.in_kernel_mode = 0;
    printf("Memory Protection: Base=0x%X, Limit=%u bytes\n", 
           base, limit);
}

// Simulate memory access with protection check
int access_memory(unsigned int address, int write) {
    // Check if in kernel mode
    if (pmu.in_kernel_mode) {
        printf("KERNEL MODE: Access granted to address 0x%X\n", address);
        return 1; // Access granted
    }

    // User mode: check bounds
    unsigned int offset = address - pmu.base_register;

    if (offset >= pmu.limit_register) {
        printf("PROTECTION FAULT: Address 0x%X out of bounds!\n", address);
        printf("   Offset %u >= Limit %u\n", offset, pmu.limit_register);
        return 0; // Access denied
    }

    printf("USER MODE: Access granted to address 0x%X\n", address);
    return 1;
}

// System call - switches to kernel mode
void kernel_access(unsigned int address) {
    pmu.in_kernel_mode = 1;
    printf("\n=== SYSTEM CALL: Entering Kernel Mode ===\n");
    access_memory(address, 1);
    pmu.in_kernel_mode = 0;
    printf("=== Returning to User Mode ===\n\n");
}

int main() {
    // Initialize with base address 0x1000 and 1024 byte limit
    init_protection(0x1000, 1024);

    printf("\n--- Testing User Mode Access ---\n");
    access_memory(0x1400, 1);  // Within bounds - OK
    access_memory(0x1800, 1);  // Out of bounds - Protection Fault

    printf("\n--- Testing Kernel Mode Access ---\n");
    kernel_access(0xFFFF);  // Any address works in kernel mode

    return 0;
}
